class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        if (num2 == 0) return num1 == 0 ? 0 : -1;
        int operations = 0;
        while (num1 != 0) {
            if (num1 * num2 < 0) {
                operations++;
                num1 += num2;
            } else if (num1 > 0) {
                int i = 30;
                while (i >= 0 && (2 * i + num2) > num1) i--;
                if (i < 0) return -1;
                operations++;
                num1 -= (2 * i + num2);
            } else {
                int i = 0;
                while (i <= 30 && (2 * i + num2) < num1) i++;
                if (i > 30) return -1;
                operations++;
                num1 -= (2 * i + num2);
            }
        }
        return operations;
    }
};
